window.TrelloPowerUp.initialize({
    'board-buttons': function () {
        return [{
            icon: 'https://cdn.glitch.com/1b42d7fe-bda8-4af8-a6c8-eff0cea9e08a%2Frocket-ship.png?1494946700421',
            text: 'Pivot Table',
            callback: function (t) {
                return t.board('all').then(async function (board) {
                    const members = board.members.filter(member => process.env.MEMBERS.includes(member.nickname));
                    const labels = board.labels.filter(label => process.env.LABELS.includes(label.name));
                    const lists = await t.lists('all');
                    const cards = await t.cards('all');
                    console.log(members);
                    console.log(labels);
                    console.log(lists);
                    console.log(cards);
                });
            }
        }];
    },
});
